changeSet.sql:
CREATE TABLE IF NOT EXISTS platform_admins ( id BIGSERIAL PRIMARY KEY, email VARCHAR(255) NOT NULL UNIQUE, full_name VARCHAR(200) NOT NULL, password_hash VARCHAR(255) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'ACTIVE', failed_login_attempts INT NOT NULL DEFAULT 0, locked_until TIMESTAMPTZ, last_login_at TIMESTAMPTZ, version INT NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by BIGINT, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by BIGINT, deleted_at TIMESTAMPTZ, CONSTRAINT ck_platform_admins_status CHECK (status IN ('ACTIVE','LOCKED','DISABLED')) );
CREATE INDEX IF NOT EXISTS ix_platform_admins_status ON platform_admins (status);
-- Platform access must not be granted through tenant roles. UPDATE role_permissions SET deleted_at = coalesce(deleted_at, now()), updated_at = now(), version = version + 1 WHERE permission_id IN (SELECT id FROM permissions WHERE code = 'PLATFORM_ADMIN') AND deleted_at IS NULL;
